#include<bits/stdc++.h>
using namespace std;
long long x,y,n;
long long fpow(long long num,long long base,long long mod){
	long long res=1;
	while(base!=0){
		if(base%2==1)res=res*num%mod;
		base/=2;
		num=num*num%mod;
	}
	return res;
}
int main(){
	cin>>x>>y>>n;
	cout<<x*fpow(10,n-1,y)*10/y%10<<x*fpow(10,n,y)*10/y%10<<x*fpow(10,n+1,y)*10/y%10;
	return 0;
}
